INSERT INTO transfer_targets VALUES(24,'2026-summer','Martin Baturina','바투리나',1090019,'Como','AM','LW','MEDIUM-HIGH','421117X542862104420011000',32.60000000000000142,58.39999999999999858,6,7.099999999999999645,'w_insidefwd','Attack','w_wideplm','Build-Up',0.75,'DATA KEY: billed as a No.10 but his measured grid fits Villa''s LEFT slot better than CAM — LM/wm-kernel 0.80 (wm_wideplm/Attack), W-kernel 0.75, vs CAM 0.68. Same left-halfspace pattern as Rogers (optimal LEFT) — direct Rogers competition/rotation rather than pure Buendia cover. Deep build-up involvement (LDM cosine 0.78) marks him as a drop-in creator, not a touchline winger.','SofaScore API player 1090019 (2026-07-02)','MEDIUM-HIGH; slot preference is HIGH-confidence (measured).');
INSERT INTO transfer_targets VALUES(25,'2026-summer','Ilaix Moriba','모리바',962890,'Celta Vigo','DM/CM','LDM','MEDIUM','0000026550276422X85111110',45.39999999999999858,45.29999999999999715,6,6.950000000000000177,'dm_holding','Ball-Winning','dm_dlp','Roaming',0.8000000000000000444,'Football Insider (tier-2): Villa readying ~£15m offer vs Celta ask £25m (release clause ~€30m); Celta need a PSR sale; Emery long-term admirer, wages no problem; Brighton in contention, Porto/Sociedad monitoring. Measured (last 6 x 90min, all La Liga): centre-left pivot (45.4,45.3) — THIRD left-lane DM candidate, same DLP/Roaming movement family as Lopy (0.84) and Fernandes (0.80); avg 6.95. Stats caveat: highest tackle volume at Celta (3.1/90) → prescription Holding/Ball-Winning despite playmaker-like footprint. [2026-07-03 watch: Yahoo/Football Insider — "pursuit intensifies", Villa to BLOCK midfield sales to fund it; £15m bid vs £25m ask, Celta SD (Garces) firm near €30m, rejected €15m Galatasaray. £10m gap unresolved → grade unchanged.] [갱신 2026-07-04] £15m 오퍼 준비, 셀타비고 희망가 £25m — £10m 갭. 브라이튼·갈라타사라이·유벤투스도 관심.','https://www.footballinsider247.com/aston-villa/transfers/sources-aston-villa-ready-ilaix-moriba-offer-thats-10m-below-asking-price ; https://www.sportsboom.co.uk/football/transfer-news/exclusive-premier-league-giants-prepare-for-a-battle-over-ilaix-moriba ; SofaScore API player 962890 (2026-07-02)','MEDIUM — tier-2 (Football Insider) offer-preparation report; measured HIGH (6 full 90s, single-club sample). 갱신: 2티어(Football Insider) 오퍼 준비 보도로 재확인.');
