INSERT INTO transfer_targets VALUES(27,'2026-summer','James Trafford','트래포드',980643,'Manchester City','GK','GK','MEDIUM-HIGH','0000000000000000020001X10',50.0,10.59999999999999965,6,7.049999999999999823,'gk_sweeper','Build-Up','gk_goalkeeper','Balanced',0.969999999999999974,'ROMANO (tier-1, 2026-07-02): on Villa''s 3-GK Martínez-succession shortlist alongside Suzuki (3rd unnamed); pursuit conditional on Martínez leaving (Juventus talks). City ask £35-40m; Liverpool/Chelsea/Spurs/Newcastle also interested. Measured (last 6 x 45+min: 4 City + 2 England): goal-line GK (50.0,10.6), fit gk_goalkeeper/Balanced 0.97, avg 7.05 incl. 8.8 vs Liverpool. Sample caveat: Donnarumma understudy — limited league minutes, sample spans Mar-Jun. Same sweeper/build-up retraining question as all GK targets.','https://www.teamtalk.com/aston-villa/villa-scouting-parma-keeper-zion-suzuki-three-man-shortlist-replace-emiliano-martinez ; https://www.givemesport.com/aston-villa-man-city-star-james-trafford-transfer-news/ ; SofaScore API player 980643 (2026-07-02)','MEDIUM-HIGH — tier-1 (Romano) shortlist confirmation; conditional on Martínez exit; measured HIGH with sparse-minutes caveat.');
