INSERT INTO transfer_targets VALUES(30,'2026-summer','Tammy Abraham','타미 아브라함',610766,'Aston Villa','ST','ST','OWNED','01855255648X8415422010200',47.39999999999999858,59.0,4,6.849999999999999645,'st_target','Attack','st_false9','Attack',0.5200000000000000177,'ALREADY OWNED: 2026-01-27 베식타슈에서 ~£18m로 빌라 복귀(1일 만에 재이적), 그 시즌 유로파리그 우승. 여름 루머 대상이 아니라 보유 선수(알리송과 동일 케이스) — 사용자 요청으로 OWNED ST 옵션으로 편입. 실측(반시즌 통틀어 45분+ 4경기 전부 ST): 중앙-약간좌측·깊은 풋프린트 (47.4,59.0), 평균 6.85. 최근접 st_false9/Attack 0.52 — 왓킨스(st_advanced 자기커널)·기라시 0.80·브로베이 0.75·파르도 0.87보다 명확히 낮음. 처방은 타깃/홀드업 아키타입 반영 st_target/Attack. 표본 캐비앳: 왓킨스의 로테이션 백업이라 45분+ 경기가 반시즌 4경기뿐이고 전부 교체 출전(추격 상황 드롭) → 깊은 편향된 풋프린트, 선발 표본 아님.','https://www.avfc.co.uk/news/2026/january/27/signing-aston-villa-confirm-tammy-abraham-signing/ ; SofaScore API player 610766 (2026-07-03)','OWNED — 이적 루머 아님(2026-01 합류확정 보유선수). 측정 신뢰 MEDIUM(표본 4경기·전부 교체출전·맥락 편향, 45분+ 6경기 미달).');
INSERT INTO transfer_targets VALUES(31,'2026-summer','Leandro Trossard','트로사르',135666,'Arsenal','LW/RW','LM','MEDIUM','120112221142232XX46344333',42.39999999999999858,62.89999999999999858,6,7.570000000000000284,'wm_widemid','Defend','wm_widemid','Defend',0.6099999999999999867,'2026-07 스캔: TransferFeed 언급 + Football Insider(2티어) "open to Aston Villa move, Arsenal ready to sanction exit" 단독 보도. 협상설(Arsenal in talks)이 있으나 2티어 1곳뿐이라 보수적으로 MEDIUM 채택. 측정: 최근 6경기(45분+) 중 5경기가 2026 월드컵 벨기에 대표팀(조별예선+16강), 1경기만 아스날 UCL — 대표팀 편중 표본 캐비앳. 좌측 하프스페이스~측면 집중(LM 슬롯 wm_widemid/Defend 적합 0.61).','https://www.footballinsider247.com/aston-villa/transfers/sources-leandro-trossard-open-to-aston-villa-move-arsenal-ready-to-sanction-exit ; https://www.transferfeed.com/clubs/aston-villa/15 ; SofaScore player 135666','MEDIUM — Football Insider(2티어) 단독 관심/협상 보도, tier-1 교차확인 없음; 측정 신뢰 MEDIUM(표본 5/6=국가대표 월드컵, 클럽 표본 희소)');
INSERT INTO transfer_targets VALUES(32,'2026-summer','Robin Risser','로빈 리세르',1387161,'RC Lens','GK','GK','MEDIUM','0000000000000000000001X20',53.10000000000000142,9.59999999999999965,6,6.879999999999999894,'gk_sweeper','Build-Up','gk_goalkeeper','Defend',0.979999999999999983,'마르티네스의 유벤투스 이적 논의를 전제로 부상한 대체 후보. 릴 21세 라리가1 GK of the Year, 최근 6경기(리그1+쿠프드프랑스, 45분+) 실측 히트맵은 라인 자체가 매우 낮고 좁게 응집 — gk_goalkeeper/Defend 커널과 0.98 유사도로 예리하게 일치. 다만 Lens는 매각 의사가 낮고(고액 필요), 뉴캐슬·토트넘도 경쟁 중이라 실현 가능성은 유동적.','https://www.getfootballnewsfrance.com/2026/aston-villa-preparing-opening-offer-for-lenss-robin-risser/; https://sports.yahoo.com/articles/aston-villa-preparing-opening-offer-195000089.html','MEDIUM — 2티어(Get French Football News) 1곳 구체적 보도, 라이벌 다수. 히트맵 HIGH (SofaScore API 멀티매치, 단일클럽 리그1 표본).');
INSERT INTO transfer_targets VALUES(33,'2026-summer','Lloyd Kelly','로이드 켈리',865167,'Juventus','CB/LB','LCB','MEDIUM','0000012100351003X21022200',31.0,38.89999999999999858,6,7.080000000000000071,'cb_bpd','Build-Up','cb_bpd','Aggressive',0.910000000000000031,'왼발 센터백 겸 레프트백 — 밍스 노쇠화의 프리미어리그 검증된 대체자로 부상. 세리에A 최근 6경기(45분+) 실측: cb_bpd/Aggressive와 0.91 유사도로 빌드업형 CB 성향 확인, 파우 토레스와 유사한 프로필. 유벤투스 희망가 €35m, 실제 협상가는 €30m선 추정. 노팅엄 포레스트·뉴캐슬도 관심.','https://readastonvilla.com/2026/06/15/aston-villa-in-lloyd-kelly-race-transfer-juventus-2026/; https://www.getfootballnewsitaly.com/2026/juventus-lloyd-kelly-leeds-united-and-aston-villa-interested-in-defender/','MEDIUM — 2티어급(Get Italian Football News) + 다수 2/3티어 교차보도, 리즈·포레스트 등 경쟁 다수. 히트맵 HIGH (세리에A 단일클럽 6경기).');
