INSERT INTO transfer_targets VALUES(35,'2026-summer','Lucas Bergvall','루카스 베리발',1391251,'Tottenham Hotspur','CM/CAM','CAM','MEDIUM-HIGH','312344225X256352546411222',56.60000000000000142,53.10000000000000142,6,6.629999999999999894,'cam_playmaker','Roaming','cam_halfwinger','Balanced',0.660000000000000031,'토트넘에 이적 요청, 첼시와 "open race" 경쟁 중 — Football Insider(2티어) 협상 재점화 보도. 다만 최근 수개월 스퍼스에서 출전시간이 크게 줄어(9~27분 다수) 45분+ 기준 표본은 3~5월 구간까지 소급 확보. 실측 히트맵은 중원 전역에 분산돼 로밍형 성향은 보이나 cam_halfwinger/Balanced와 0.66으로 중간 수준 적합 — 벤치 표본 편향 가능성에 유의.','https://www.footballinsider247.com/aston-villa/transfers/sources-aston-villa-to-reignite-lucas-bergvall-pursuit-amid-open-race-for-tottenham-deal; https://readastonvilla.com/2026/06/26/aston-villa-lucas-bergvall-transfer-opening/','MEDIUM-HIGH — 2티어(Football Insider) 협상 재점화+토트넘과 논의 개시 보도. 히트맵 MEDIUM (최근 출전시간 부족으로 3월까지 소급, 벤치 편향 캐비앗).');
INSERT INTO transfer_targets VALUES(36,'2026-summer','Nick Woltemade','닉 볼테마데',980623,'Newcastle United','ST','ST','MEDIUM','11421357X2332332111101110',50.5,61.79999999999999716,6,6.730000000000000426,'st_advanced','Versatile','st_false9','Build-Up',0.7900000000000000355,'뉴캐슬 1시즌만에 이적 논의 — 독일 대표 스트라이커, 아틀레티코·도르트문트도 관심. 프리미어리그 최근 6경기(45분+) 실측 st_false9/Build-Up 0.79로 처지는 폴스나인형 움직임 확인, 왓킨스와 결이 다름(왓킨스는 채널런 중심). 뉴캐슬 희망가 €65m, 로테이션 불만이 이적 동기.','https://cryptobriefing.com/aston-villa-woltemade-newcastle-transfer/; https://www.sportsmole.co.uk/football/newcastle-united/transfer-talk/news/newcastle-set-woltemade-asking-price-amid-villa-european-giants-interest_599733.html','MEDIUM — 지역지(Express & Star)+전국 아웃렛 교차보도, 아틀레티코·도르트문트 등 경쟁 다자간, roundtable.io는 "성사 어려움" 반대신호. 히트맵 HIGH (프리미어리그 단일클럽 6경기).');
INSERT INTO transfer_targets VALUES(37,'2026-summer','Nicolas Jackson','니콜라스 잭슨',1085381,'Chelsea (on loan: Bayern Munich)','ST','ST','HIGH','457725X496434211211100000',48.0,68.70000000000000284,6,7.450000000000000177,'st_advanced','Attack','st_advanced','Support',0.7520000000000000017,'왓킨스 후계 앵글: 에메리가 비야레알에서 지도한 인연, 첼시서 입지 상실+바이에른 임대 성과 불확실로 이적 유력. 최근 6경기(분데스리가+DFB포칼+UCL, 45분+) 실측 히트맵 중심좌표(48.0,68.7) — 좌우 편차 거의 없는 순수 중앙 전진형, st_advanced/Support 0.75로 왓킨스와 동일 역할군(st_advanced). 폴스나인형(볼테마데 0.79/기라시 0.80)보다 수치는 낮지만 스타일 계승 측면에서 왓킨스와 가장 가까운 후보.','https://www.skysports.com/football/news/11677/13415336/nicolas-jackson-transfer-news-aston-villa-interested-in-signing-chelsea-striker-after-exploring-conditions-of-deal ; https://www.givemesport.com/newcastle-transfer-news-aston-villa-chelsea-nicolas-jackson-fabrizio-romano-exclusive/ ; SofaScore API player 1085381 (2026-07-05)','HIGH — 1티어 2곳(Sky Sports "조건 탐색 중" + Romano "결정 임박") 교차 확인. 히트맵 HIGH (분데스리가 단일클럽 6경기, 45분+ 전부, F포지션 순수).');
INSERT INTO transfer_targets VALUES(38,'2026-summer','William Osula','윌리엄 오슬라',1122603,'Newcastle United','ST','ST','MEDIUM-LOW','5597247X58125410121100000',50.39999999999999858,71.0,5,7.599999999999999645,'st_advanced','Attack','st_advanced','Support',0.7469999999999999974,'왓킨스 후계 앵글: 최근 breakthrough 시즌(최근 8경기 6골, PL 9골 이상 선수 중 전환율 30%로 최고)으로 빌라·에버턴 동시 관심. 프리미어리그 5경기(45분+·히트포인트15+만; 66분 1경기는 10포인트로 제외해 표본 5) 실측 히트맵 중심좌표(50.4,71) — 좌우 편차 거의 없는 순수 중앙형, st_advanced/Support 0.747로 왓킨스와 동일 역할군. 잭슨(0.752)과 사실상 동급 — 스타일 계승 후보로는 최상위권. 다만 뉴캐슬이 매각 의사 없다는 보도도 혼재.','https://readastonvilla.com/2026/05/22/aston-villa-william-osula-newcastle-transfer-watkins-successor-2026/ ; https://www.sportsmole.co.uk/football/newcastle-united/transfer-talk/news/thats-been-the-focus-newcastles-osula-lifts-lid-on-future-amid-transfer-talk_593397.html ; SofaScore API player 1122603 (2026-07-05)','MEDIUM-LOW — 3티어(팬사이트/어그리게이터: readastonvilla, sportsmole 등)만 확인, 1~2티어(Romano/Athletic/Sky/BBC 등) 미확인. 히트맵 HIGH (프리미어리그 단일클럽 5경기, 45분+·15+ 히트포인트).');
